1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Step = { op: string; items: Item[] };
6	type Customer = { yearsWithMHPCO?: number };
7	type Input = { customer?: Customer; steps: Step[] };
8	
9	const COMPONENT_PREMIUM = 33;
10	const HIGHLY_ENCHANTED_MIN = 5;
11	const LOYALTY_MIN_YEARS = 2;
12	
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	const COMPONENT_UNIT_PRICE = 25;
16	
17	const COMPONENT_TYPES = ["rune", "moonstone"] as const;
18	
19	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
20	  sword: 115,
21	  amulet: 71,
22	  staff: 93,
23	  potion: 49,
24	  rune: COMPONENT_PREMIUM,
25	  moonstone: COMPONENT_PREMIUM,
26	};
27	
28	const isComponent = (item: Item): boolean =>
29	  (COMPONENT_TYPES as readonly string[]).includes(item.type);
30	
31	const isHighlyEnchanted = (item: Item): boolean =>
32	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_MIN;
33	
34	const hasLoyalty = (customer: Customer | undefined): boolean =>
35	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MIN_YEARS;
36	
37	const isAfterFirstStep = (stepIndex: number): boolean => stepIndex >= 1;
38	
39	const isMultiComponentStep = (step: Step): boolean =>
40	  step.items.length >= 2 && step.items.every(isComponent);
41	
42	const baseForComponentCount = (count: number): number => {
43	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
44	  const residual = count % COMPONENT_BLOCK_SIZE;
45	  return blocks * COMPONENT_BLOCK_PRICE + residual * COMPONENT_UNIT_PRICE;
46	};
47	
48	const componentStepBase = (step: Step): number =>
49	  COMPONENT_TYPES.reduce((sum, type) => {
50	    const count = step.items.filter((i) => i.type === type).length;
51	    return sum + baseForComponentCount(count);
52	  }, 0);
53	
54	const firstContractPremium = (base: number): number =>
55	  Math.ceil((base * 11) / 10) + 5;
56	
57	export function runScenario(input: unknown): ScenarioOutput {
58	  const { customer, steps } = input as Input;
59	  const results = steps.map((step, stepIndex) => {
60	    const item = step.items[0];
61	    if (isMultiComponentStep(step)) {
62	      return { premium: firstContractPremium(componentStepBase(step)) };
63	    }
64	    if (item.cursed) {
65	      return { premium: 170 };
66	    }
67	    if (isHighlyEnchanted(item)) {
68	      return { premium: 148 };
69	    }
70	    if (hasLoyalty(customer)) {
71	      return { premium: 93 };
72	    }
73	    if (isAfterFirstStep(stepIndex)) {
74	      return { premium: 90 };
75	    }
76	    return { premium: PREMIUM_BY_ITEM_TYPE[item.type] };
77	  });
78	  return { results };
79	}
